const content = Buffer.from($json.content, 'base64').toString('utf-8');
const webUrl = $('Prepare Webhook Data').item.json.web_url;
const updatedContent = content.replace(/const val WEBSITE_URL = ".*?"/g, `const val WEBSITE_URL = "${webUrl}"`);
const encodedContent = Buffer.from(updatedContent).toString('base64');

return [{
  json: {
    content: encodedContent,
    sha: $json.sha,
    message: 'Update website URL',
    branch: $('Prepare Webhook Data').item.json.github_branch
  }
}];

const content = Buffer.from($json.content, 'base64').toString('utf-8');
const appName = $('Prepare Webhook Data').item.json.app_name;
const updatedContent = content.replace(/<string name="app_name">.*?<\/string>/g, `<string name="app_name">${appName}</string>`);
const encodedContent = Buffer.from(updatedContent).toString('base64');
return [{ json: { content: encodedContent, sha: $json.sha, message: 'Update app name', branch: $('Prepare Webhook Data').item.json.github_branch } }];

// get app name safely
const appNameRaw = $input.first().json.body?.name || "myapp";

// sanitize
const appName = appNameRaw
  .toLowerCase()
  .replace(/[^a-z0-9]/g, "");

// new applicationId
const newAppId = `com.${appName}.webview`;

// decode base64 → text
const original = Buffer.from(
  $input.first().json.content,
  "base64"
).toString("utf-8");

// replace applicationId
const updatedGradle = original.replace(
  /applicationId\s*=\s*".*?"/,
  `applicationId = "${newAppId}"`
);

return {
  fileContent: updatedGradle,
  applicationId: newAppId
};
